package app

const appCSS = `
:root{color-scheme:dark;--bg:#080b12;--panel:#111827;--panel2:#172033;--text:#edf2ff;--muted:#94a3b8;--brand:#8b5cf6;--brand2:#06b6d4;--ok:#22c55e;--bad:#ef4444;--warn:#f59e0b;--line:#263244}*{box-sizing:border-box}body{margin:0;background:radial-gradient(circle at top left,#1e1b4b,transparent 36rem),linear-gradient(135deg,#080b12,#101827 55%,#0d111b);color:var(--text);font-family:Inter,ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif}a{color:#a5b4fc;text-decoration:none}code{background:#020617;border:1px solid var(--line);border-radius:.45rem;padding:.1rem .35rem}.nav{position:sticky;top:0;z-index:10;display:flex;gap:1rem;align-items:center;padding:1rem clamp(1rem,4vw,3rem);background:rgba(8,11,18,.78);backdrop-filter:blur(16px);border-bottom:1px solid var(--line)}.brand{font-weight:800;color:white;margin-right:1rem}.logout{margin-left:auto}.shell{width:min(1180px,calc(100% - 2rem));margin:2rem auto 5rem}.hero{display:flex;justify-content:space-between;gap:2rem;align-items:center;padding:2rem;border:1px solid rgba(139,92,246,.38);border-radius:1.5rem;background:linear-gradient(135deg,rgba(139,92,246,.22),rgba(6,182,212,.12));box-shadow:0 24px 80px rgba(0,0,0,.35)}.hero h1{font-size:clamp(2rem,5vw,4rem);line-height:1;margin:.2rem 0 1rem;max-width:850px}.eyebrow{text-transform:uppercase;letter-spacing:.16em;color:#67e8f9;font-weight:800;font-size:.78rem}.grid{display:grid;gap:1rem}.stats{grid-template-columns:repeat(4,minmax(0,1fr));margin:1rem 0}.stats article,.panel,.host-card,.host-list article{background:rgba(17,24,39,.86);border:1px solid var(--line);border-radius:1.1rem;padding:1.1rem;box-shadow:0 12px 40px rgba(0,0,0,.18)}.stats span,.muted{color:var(--muted)}.stats strong{display:block;font-size:1.35rem;margin-top:.35rem}.panel{margin:1rem 0}.panel-head{display:flex;align-items:center;justify-content:space-between;gap:1rem}.inline{display:flex;gap:.75rem;align-items:end;flex-wrap:wrap}.host-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(190px,1fr));gap:1rem}.host-card h3{margin-top:0}.host-card.success{border-color:rgba(34,197,94,.45)}.host-card.failed{border-color:rgba(239,68,68,.55)}.host-card.running{border-color:rgba(6,182,212,.6)}.host-list{display:grid;gap:.8rem}.host-list article{display:grid;grid-template-columns:1fr auto auto;align-items:center;gap:1rem}button,select,input{font:inherit}button{border:0;border-radius:.75rem;padding:.78rem 1rem;background:linear-gradient(135deg,var(--brand),var(--brand2));color:white;font-weight:800;cursor:pointer}.secondary{background:#1f2937;border:1px solid var(--line)}select,input{width:100%;border:1px solid var(--line);border-radius:.75rem;background:#020617;color:var(--text);padding:.8rem}label{display:grid;gap:.35rem;margin:.75rem 0;color:var(--muted)}.table-wrap{overflow:auto}table{width:100%;border-collapse:collapse}th,td{text-align:left;padding:.8rem;border-bottom:1px solid var(--line)}th{color:var(--muted);font-size:.86rem}.badge{display:inline-flex;border-radius:999px;padding:.2rem .55rem;background:#334155;font-weight:800;font-size:.8rem}.badge.success{background:rgba(34,197,94,.18);color:#86efac}.badge.failed{background:rgba(239,68,68,.18);color:#fca5a5}.badge.running{background:rgba(6,182,212,.18);color:#67e8f9}.badge.cancelled{background:rgba(245,158,11,.18);color:#fcd34d}.log{white-space:pre-wrap;overflow:auto;background:#020617;border:1px solid var(--line);border-radius:1rem;padding:1rem;min-height:20rem}.error{background:rgba(239,68,68,.14);border:1px solid rgba(239,68,68,.45);color:#fecaca;padding:.8rem;border-radius:.8rem}.auth{min-height:100vh;display:grid;place-items:center;padding:1rem}.auth-card{width:min(460px,100%);padding:2rem;border-radius:1.5rem;background:rgba(17,24,39,.9);border:1px solid var(--line);box-shadow:0 24px 100px rgba(0,0,0,.45)}.auth-card h1{font-size:2.4rem;margin:.2rem 0}.switch input{display:none}.switch span{display:block;width:3.2rem;height:1.7rem;background:#334155;border-radius:999px;position:relative}.switch span:before{content:"";position:absolute;width:1.25rem;height:1.25rem;border-radius:999px;background:white;left:.22rem;top:.22rem;transition:.18s}.switch input:checked+span{background:linear-gradient(135deg,var(--brand),var(--brand2))}.switch input:checked+span:before{transform:translateX(1.5rem)}.examples{margin-top:1rem;color:var(--muted);overflow:auto}@media(max-width:760px){.nav{overflow:auto}.hero{display:block}.stats{grid-template-columns:1fr 1fr}.host-list article{grid-template-columns:1fr}.logout{margin-left:0}}`
